#!/usr/bin/env python3
"""
Pxtly Mock Data Generator
Generates fully anonymized, synthetic compliance and transactional data.
All commercial names and real-world identifiers have been removed.
"""

import base64
import os
import zlib

FILES_DATA = {
    "csv/asset_valuations_history.csv": "",
    "csv/organizations.csv": "",
    "csv/transactions_history.csv": "",
    "json/compliance_kyc_aml.json": "",
    "json/fabric_wallets.json": "",
    "json/fabric_world_state.json": ""
}

def generate_fixtures(base_dir="fixtures"):
    os.makedirs(base_dir, exist_ok=True)
    os.makedirs(os.path.join(base_dir, "csv"), exist_ok=True)
    os.makedirs(os.path.join(base_dir, "json"), exist_ok=True)
    
    for rel_path, encoded_data in FILES_DATA.items():
        compressed = base64.b64decode(encoded_data)
        data = zlib.decompress(compressed)
        
        target_path = os.path.join(base_dir, rel_path)
        with open(target_path, 'wb') as f:
            f.write(data)
        print(f"Generated clean mock data: {target_path}")

if __name__ == "__main__":
    current_dir = os.path.dirname(os.path.abspath(__file__))
    fixtures_dir = os.path.join(current_dir, "fixtures")
    generate_fixtures(fixtures_dir)
    print("Mock data generation complete. Safe for testing and local usage.")
